/// Retrieve the last error set by the FFI layer, if any.
/// Returns a slice into thread-local storage valid until the next FFI call.
pub fn _last_error() ?[]const u8 {
    const _code = c.kreuzberg_last_error_code();
    if (_code == 0) return null;
    const _ctx = c.kreuzberg_last_error_context();
    if (_ctx == null) return null;
    return std.mem.sliceTo(_ctx, 0);
}

/// Map the last FFI error to a typed error from the given error set.
/// Coarse fallback: returns the first declared variant. Per-code dispatch
/// will replace this once the IR exposes per-variant numeric codes.
inline fn _first_error(comptime E: type) E {
    const fields = @typeInfo(E).error_set orelse return @as(E, error.Unknown);
    if (fields.len == 0) unreachable;
    return @field(E, fields[0].name);
}

